  state.achievements.unshift({ goalId: goal.id, type: 'goal', title: goal.title, area: goal.area, targetValue: goal.targetValue, unit: goal.unit || '', achievedAt: new Date().toISOString(), colorIndex: goal.colorIndex });
  return true;
