function updateKnowledgeGraphDom() { if (!knowledgeGraphModel) return; knowledgeGraphModel.nodes.forEach((node) => { const point = knowledgeGraphModel.positions.get(node.key); const group = [...knowledgeGraph.querySelectorAll('[data-knowledge-node-key]')].find((element) => element.getAttribute('data-knowledge-node-key') === node.key); if (!group || !point) return; const left = point.x - node.width / 2; const top = point.y - node.height / 2; const textX = left + 16; const textY = top + 16; const rect = group.querySelector('rect:not(.knowledge-node-clip)'); rect.setAttribute('x', left); rect.setAttribute('y', top); rect.setAttribute('width', node.width); rect.setAttribute('height', node.height); const clip = group.querySelector('.knowledge-node-clip'); clip.setAttribute('x', textX); clip.setAttribute('y', textY); clip.setAttribute('width', node.width - 32); clip.setAttribute('height', node.height - 32); const text = group.querySelector('.knowledge-node-name'); text.setAttribute('x', textX); text.setAttribute('y', textY); text.querySelectorAll('tspan').forEach((line, index) => { line.setAttribute('x', textX); line.setAttribute('dy', index ? 18 : 0); }); }); knowledgeGraphModel.edges.forEach(([from, to], index) => { const line = knowledgeGraph.querySelector(`[data-knowledge-edge="${index}"]`); const left = knowledgeGraphModel.positions.get(from); const right = knowledgeGraphModel.positions.get(to); if (!line || !left || !right) return; line.setAttribute('x1', left.x); line.setAttribute('y1', left.y); line.setAttribute('x2', right.x); line.setAttribute('y2', right.y); }); }
function updateKnowledgeSelectionDom() { const selectedKey = selectedKnowledgeId ? `knowledge:${selectedKnowledgeId}` : ''; knowledgeGraph.querySelectorAll('[data-knowledge-node-key]').forEach((node) => node.classList.toggle('is-selected', node.getAttribute('data-knowledge-node-key') === selectedKey)); knowledgeGraphModel?.edges.forEach(([from, to], index) => knowledgeGraph.querySelector(`[data-knowledge-edge="${index}"]`)?.classList.toggle('is-selected', from === selectedKey || to === selectedKey)); $('#clearKnowledgeSelection').hidden = !selectedKnowledgeId; }
function stopKnowledgeSimulation() { if (knowledgeSimulationFrame) cancelAnimationFrame(knowledgeSimulationFrame); knowledgeSimulationFrame = null; }
function saveKnowledgeGraphPositions() { if (!knowledgeGraphModel) return; const padding = knowledgeGraphPadding(knowledgeGraphModel.nodes); state.knowledgeGraphPositions ||= {}; knowledgeGraphModel.nodes.forEach((node) => { const item = knowledgeGraphModel.positions.get(node.key); state.knowledgeGraphPositions[node.key] = { x: (item.x - padding) / (knowledgeGraphModel.width - padding * 2), y: (item.y - padding) / (knowledgeGraphModel.height - padding * 2) }; }); persist(); }
function startKnowledgeSimulation() { stopKnowledgeSimulation(); if (!knowledgeGraphModel?.shouldAnimate || !document.querySelector('[data-view-panel="knowledge"]')?.classList.contains('is-active')) return; knowledgeSimulationTicks = 240; const tick = () => { const model = knowledgeGraphModel; if (!model || !model.shouldAnimate || !document.querySelector('[data-view-panel="knowledge"]')?.classList.contains('is-active')) return stopKnowledgeSimulation(); const isDragging = knowledgeDragState?.mode === 'node'; const pinned = isDragging ? new Set(knowledgeDragState.originals.keys()) : new Set(); const alpha = isDragging ? .26 : model.simulationAlpha ?? .22; advanceKnowledgeSimulation(model, pinned, alpha); model.simulationAlpha = isDragging ? .26 : alpha * .975; updateKnowledgeGraphDom(); if (!isDragging) knowledgeSimulationTicks -= 1; if (isDragging || (knowledgeSimulationTicks > 0 && model.simulationAlpha > .018)) knowledgeSimulationFrame = requestAnimationFrame(tick); else { model.shouldAnimate = false; model.simulationAlpha = 0; knowledgeSimulationFrame = null; saveKnowledgeGraphPositions(); } }; knowledgeSimulationFrame = requestAnimationFrame(tick); }
knowledgeGraph.addEventListener('pointerdown', (event) => { const node = event.target.closest('[data-knowledge-node-key]'); const point = knowledgeGraphPoint(event); if (!point || !knowledgeGraphModel) return; const svg = knowledgeGraph.querySelector('[data-knowledge-svg]'); if (!node) { knowledgeDragState = { mode: 'pan', pointerId: event.pointerId, start: point, originalView: { ...knowledgeGraphModel.view }, moved: false }; svg?.setPointerCapture(event.pointerId); event.preventDefault(); return; } const key = node.getAttribute('data-knowledge-node-key'); const item = knowledgeGraphModel.positions.get(key); const originals = new Map([[key, { x: item.x, y: item.y }]]); knowledgeDragState = { mode: 'node', pointerId: event.pointerId, startKey: key, start: point, originals, moved: false }; knowledgeGraphModel.shouldAnimate = true; knowledgeGraphModel.simulationAlpha = .32; svg?.setPointerCapture(event.pointerId); startKnowledgeSimulation(); event.preventDefault(); });
knowledgeGraph.addEventListener('pointermove', (event) => { if (!knowledgeDragState || knowledgeDragState.pointerId !== event.pointerId) return; const point = knowledgeGraphPoint(event); if (!point) return; const dx = point.x - knowledgeDragState.start.x; const dy = point.y - knowledgeDragState.start.y; if (Math.hypot(dx, dy) > 4) knowledgeDragState.moved = true; if (knowledgeDragState.mode === 'pan') { const view = knowledgeDragState.originalView; knowledgeGraphModel.view = { ...view, x: Math.max(0, Math.min(knowledgeGraphModel.width - view.width, view.x - dx)), y: Math.max(0, Math.min(knowledgeGraphModel.height - view.height, view.y - dy)) }; updateKnowledgeGraphView(); return; } const padding = knowledgeGraphPadding(knowledgeGraphModel.nodes); knowledgeDragState.originals.forEach((original, key) => { const item = knowledgeGraphModel.positions.get(key); item.x = Math.max(padding, Math.min(knowledgeGraphModel.width - padding, original.x + dx)); item.y = Math.max(padding, Math.min(knowledgeGraphModel.height - padding, original.y + dy)); }); updateKnowledgeGraphDom(); });
function finishKnowledgeDrag(event) { if (!knowledgeDragState || knowledgeDragState.pointerId !== event.pointerId) return; const drag = knowledgeDragState; knowledgeDragState = null; if (drag.mode === 'pan') { if (drag.moved) knowledgeIgnoreClickUntil = Date.now() + 250; return; } if (drag.moved) { knowledgeGraphModel.simulationAlpha = .26; knowledgeSimulationTicks = 180; knowledgeIgnoreClickUntil = Date.now() + 250; return; } const cardId = knowledgeGraphModel.nodes.find((node) => node.key === drag.startKey)?.cardId; if (cardId) { knowledgeIgnoreClickUntil = Date.now() + 250; openKnowledgeDetail(cardId); } }
knowledgeGraph.addEventListener('pointerup', finishKnowledgeDrag); knowledgeGraph.addEventListener('pointercancel', finishKnowledgeDrag);
knowledgeGraph.addEventListener('wheel', (event) => { if (!knowledgeGraphModel) return; event.preventDefault(); const point = knowledgeGraphPoint(event); if (!point) return; const current = knowledgeGraphModel.view; const factor = Math.exp(event.deltaY * .0015); const nextWidth = Math.max(knowledgeGraphModel.width / 3.5, Math.min(knowledgeGraphModel.width, current.width * factor)); const nextHeight = nextWidth * knowledgeGraphModel.height / knowledgeGraphModel.width; const ratioX = (point.x - current.x) / current.width; const ratioY = (point.y - current.y) / current.height; knowledgeGraphModel.view = { x: Math.max(0, Math.min(knowledgeGraphModel.width - nextWidth, point.x - nextWidth * ratioX)), y: Math.max(0, Math.min(knowledgeGraphModel.height - nextHeight, point.y - nextHeight * ratioY)), width: nextWidth, height: nextHeight }; updateKnowledgeGraphView(); }, { passive: false });
