async function hashVaultPin(pin) { const data = new TextEncoder().encode(pin); const digest = await crypto.subtle.digest('SHA-256', data); return [...new Uint8Array(digest)].map((byte) => byte.toString(16).padStart(2, '0')).join(''); }
function lockSecretVault() { vaultUnlocked = false; clearTimeout(vaultAutoLockTimer); vaultAutoLockTimer = null; const active = activeContent(); if (active?.isPrivate) state.activeContentId = state.contents.find((item) => !item.isPrivate)?.id || null; render(); }
function refreshVaultAutoLock() { if (!vaultUnlocked) return; clearTimeout(vaultAutoLockTimer); vaultAutoLockTimer = setTimeout(lockSecretVault, 5 * 60 * 1000); }
function openSecretVaultDialog() { const isSetup = !state.vaultPinHash; $('#secretVaultForm').reset(); $('#secretVaultEyebrow').textContent = isSetup ? 'SET PRIVATE COLLECTION PIN' : 'PRIVATE COLLECTION'; $('#secretVaultTitle').textContent = isSetup ? '비밀 자료함 PIN 설정' : '비밀 자료함 열기'; $('#secretVaultIntro').textContent = isSetup ? '4~12자리 숫자 PIN을 설정하세요. 이 브라우저에서 비밀 자료함을 여는 데 사용됩니다.' : 'PIN을 입력하면 5분 동안 비밀 자료함을 열 수 있어요.'; $('#secretVaultConfirmLabel').hidden = !isSetup; $('#secretVaultPinConfirm').required = isSetup; $('#saveSecretVaultButton').textContent = isSetup ? '잠금 설정' : '자료함 열기'; $('#secretVaultMessage').textContent = ''; secretVaultDialog.showModal(); $('#secretVaultPin').focus(); }
