function openContentDialog(contentId = null) { editingContentId = contentId; const item = contentId ? state.contents.find((content) => content.id === contentId) : null; $('#contentForm').reset(); $('#contentDialogEyebrow').textContent = item ? 'EDIT CONTENT' : 'NEW CONTENT'; $('#contentDialogTitle').textContent = item ? '콘텐츠 정보를 다듬어보세요.' : '새 콘텐츠를 기록해요.'; $('#removeContentCoverOption').hidden = !item?.cover; if (item) { $('#contentTitle').value = item.title; $('#contentType').value = item.type; $('#contentPlatform').value = item.platform || ''; $('#contentStatus').value = item.status || 'active'; $('#contentPrivate').checked = Boolean(item.isPrivate); $('#contentProgress').value = item.progress || ''; $('#contentUpdateDay').value = item.updateDay || ''; $('#contentNote').value = item.note || ''; if (/^https?:\/\//.test(item.cover || '')) $('#contentCoverUrl').value = item.cover; } updateContentProgressHint(); contentDialog.showModal(); $('#contentTitle').focus(); }
