function updateLorePasteStatus() { const status = $('#loreImagePasteStatus'); const clear = $('#clearLorePastedImage'); const preview = $('#loreImagePastePreview'); const hasImage = Boolean(pastedLoreImage); status.textContent = hasImage ? '사진이 붙여넣어졌어요. 저장하면 인물 사진으로 등록됩니다.' : ''; preview.hidden = !hasImage; preview.src = hasImage ? pastedLoreImage : ''; clear.hidden = !hasImage; }
