function addTapOnlyTouchHandler(element, cardSelector, ignoredSelector, onTap) { let start = null; const supportsPointer = 'PointerEvent' in window; const pointOf = (event) => event.changedTouches?.[0] || event.touches?.[0] || event; const startEvent = supportsPointer ? 'pointerdown' : 'touchstart'; const endEvent = supportsPointer ? 'pointerup' : 'touchend'; const cancelEvent = supportsPointer ? 'pointercancel' : 'touchcancel'; element.addEventListener(startEvent, (event) => { if (supportsPointer && event.pointerType === 'mouse') return; const point = pointOf(event); start = point ? { x: point.clientX, y: point.clientY } : null; }, { passive: true }); element.addEventListener(endEvent, (event) => { if (supportsPointer && event.pointerType === 'mouse') return; const point = pointOf(event); const target = event.target instanceof Element ? event.target : null; const card = target?.closest(cardSelector); const moved = !start || !point || Math.hypot(point.clientX - start.x, point.clientY - start.y) > 12; start = null; if (!card || moved || (ignoredSelector && target.closest(ignoredSelector))) return; event.preventDefault(); onTap(card); }, { passive: false }); element.addEventListener(cancelEvent, () => { start = null; }, { passive: true }); }
