function applySoxlTrade(trade, direction = 1) { const soxl = state.investments.soxl; const shares = investmentNumber(trade.shares); const price = investmentNumber(trade.price); const previousShares = investmentNumber(soxl.shares); let nextShares = previousShares; let nextAveragePrice = investmentNumber(soxl.averagePrice); if (!shares || !price) return false; if (trade.type === 'buy') { if (direction > 0) { nextAveragePrice = (previousShares * nextAveragePrice + shares * price) / (previousShares + shares); nextShares = previousShares + shares; } else { if (shares > previousShares) return false; nextShares = previousShares - shares; nextAveragePrice = nextShares ? Math.max(0, ((previousShares * nextAveragePrice) - shares * price) / nextShares) : 0; } } else if (direction > 0) { if (shares > previousShares) return false; nextShares = previousShares - shares; if (!nextShares) nextAveragePrice = 0; } else { nextShares = previousShares + shares; if (!nextAveragePrice) nextAveragePrice = price; } const purchaseAmount = nextShares * nextAveragePrice; if (direction > 0 && trade.type === 'buy' && purchaseAmount > investmentNumber(soxl.principal)) { alert('예수금이 부족해요. 먼저 투자원금을 수정해주세요.'); return false; } soxl.shares = nextShares; soxl.averagePrice = nextAveragePrice; soxl.purchaseAmount = purchaseAmount; soxl.cash = investmentNumber(soxl.principal) - purchaseAmount; soxl.valuation = nextShares * marketQuotePrice('SOXL', price); return true; }
