function backupDataUrl(blob) { return new Promise((resolve, reject) => { const reader = new FileReader(); reader.onload = () => resolve(reader.result); reader.onerror = () => reject(new Error('이미지 파일을 읽지 못했어요.')); reader.readAsDataURL(blob); }); }
async function portableMemoryImage(image) { if (!image || isLocalMemoryImage(image)) return image; if (!signedInUser || !supabaseClient) throw new Error('클라우드에 저장된 추억 사진을 백업하려면 먼저 로그인해야 해요.'); const { data, error } = await supabaseClient.storage.from('memory-images').createSignedUrl(image, 120); if (error || !data?.signedUrl) throw error || new Error('추억 사진 주소를 만들지 못했어요.'); const response = await fetch(data.signedUrl); if (!response.ok) throw new Error(`추억 사진을 내려받지 못했어요. (${response.status})`); return backupDataUrl(await response.blob()); }
async function createPortableBackup() { const backupState = cloneCloudState(state); const sources = [...new Set((backupState.memories || []).flatMap((memory) => [...(memory.images || []), memory.coverImage || '']).filter(Boolean))]; const replacements = new Map(); for (const source of sources) replacements.set(source, await portableMemoryImage(source)); backupState.memories = (backupState.memories || []).map((memory) => ({ ...memory, images: (memory.images || []).map((image) => replacements.get(image) || image), coverImage: replacements.get(memory.coverImage) || memory.coverImage || '' })); return { format: 'my-life-os-portable-backup', version: 1, exportedAt: new Date().toISOString(), data: backupState }; }
