$('#importBackupButton').addEventListener('click', async () => { const file = $('#importBackupFile').files[0]; const message = $('#backupMessage'); if (!file) { message.textContent = '복원할 .json 백업 파일을 먼저 선택해주세요.'; return; } try { const backup = JSON.parse(await file.text()); if (backup?.format !== 'my-life-os-portable-backup' || !backup.data || typeof backup.data !== 'object') throw new Error('이 앱에서 만든 백업 파일이 아니에요.'); if (!confirm('현재 브라우저의 모든 기록을 백업 파일 내용으로 바꿀까요? 이 작업은 되돌릴 수 없어요.')) return; state = cloneCloudState(backup.data); normalizeState(); normalizeKnowledgeState(); normalizeVaultState(); normalizeMemoryStorageState(); persist(); render(); message.textContent = '백업을 복원했어요. 로그인 상태라면 클라우드에도 동기화됩니다.'; } catch (error) { console.error(error); message.textContent = `복원하지 못했어요. ${error.message || '백업 파일을 확인해주세요.'}`; } });
function setActiveView(view, writeHash = true) { const allowedViews = ['today', 'character', 'goals', 'business', 'investment', 'library', 'knowledge', 'contents', 'memories', 'people']; const activeView = allowedViews.includes(view) ? view : 'today'; document.querySelectorAll('[data-view-panel]').forEach((panel) => panel.classList.toggle('is-active', panel.dataset.viewPanel === activeView)); document.querySelectorAll('.main-nav [data-nav-view]').forEach((button) => button.classList.toggle('is-active', button.dataset.navView === activeView)); safelyStoreLocal('my-life-active-view', activeView); if (writeHash && location.hash !== `#${activeView}`) location.hash = activeView; if (activeView === 'investment') refreshMarketQuotes(); if (activeView === 'knowledge') startKnowledgeSimulation(); else stopKnowledgeSimulation(); window.scrollTo({ top: 0, behavior: 'smooth' }); }
function setupPullToRefresh() { if (!window.matchMedia('(pointer: coarse)').matches) return; const threshold = 78; let startY = 0; let distance = 0; let tracking = false; const reset = () => { tracking = false; distance = 0; pullToRefresh.classList.remove('is-visible', 'is-ready', 'is-loading'); }; document.addEventListener('touchstart', (event) => { if (window.scrollY > 0 || event.touches.length !== 1) return; startY = event.touches[0].clientY; distance = 0; tracking = true; }, { passive: true }); document.addEventListener('touchmove', (event) => { if (!tracking || event.touches.length !== 1) return; const nextDistance = event.touches[0].clientY - startY; if (nextDistance <= 0 || window.scrollY > 0) { reset(); return; } distance = Math.min(nextDistance, 118); const ready = distance >= threshold; pullToRefresh.classList.add('is-visible'); pullToRefresh.classList.toggle('is-ready', ready); pullToRefreshText.textContent = ready ? '놓으면 새로고침' : '당겨서 새로고침'; if (distance > 8) event.preventDefault(); }, { passive: false }); const finish = () => { if (!tracking) return; const shouldRefresh = distance >= threshold; if (!shouldRefresh) { reset(); return; } tracking = false; pullToRefresh.classList.add('is-loading'); pullToRefreshText.textContent = '새로고침 중…'; window.setTimeout(() => window.location.reload(), 160); }; document.addEventListener('touchend', finish, { passive: true }); document.addEventListener('touchcancel', reset, { passive: true }); }
