function storagePathFromLegacySignedUrl(value) { if (typeof value !== 'string') return ''; const match = value.match(/\/storage\/v1\/object\/sign\/memory-images\/([^?]+)/); return match ? decodeURIComponent(match[1]) : ''; }
function normalizeMemoryStorageState() { let changed = false; state.memories = (state.memories || []).map((memory) => { const coverPath = storagePathFromLegacySignedUrl(memory.coverImage); if (coverPath) changed = true; return { ...memory, coverImage: coverPath || memory.coverImage || '', images: (memory.images || []).map((image) => { const value = typeof image === 'string' ? image : image?.path || image?.src || ''; const path = storagePathFromLegacySignedUrl(value); if (path) { changed = true; return path; } return value; }) }; }); return changed; }
