async function refreshMemoryImageUrls() { if (!signedInUser || !supabaseClient || memoryImageRefreshPromise) return memoryImageRefreshPromise; const paths = [...new Set((state.memories || []).flatMap((memory) => memory.images || []).filter((image) => image && !isLocalMemoryImage(image) && !memoryImageUrlCache.has(image)))]; if (!paths.length) return; memoryImageRefreshPromise = Promise.all(paths.map(async (path) => { const { data, error } = await supabaseClient.storage.from('memory-images').createSignedUrl(path, 300); if (!error && data?.signedUrl) memoryImageUrlCache.set(path, data.signedUrl); })).then(() => { renderMemories(); if ($('#memoryDetailDialog').open && activeMemoryId) openMemoryDetail(activeMemoryId); }).catch((error) => console.warn('Memory image refresh failed', error)).finally(() => { memoryImageRefreshPromise = null; }); return memoryImageRefreshPromise; }
