const memoryLocationLabel = (memory) => memory.location || (Number.isFinite(memory.latitude) && Number.isFinite(memory.longitude) ? `${memory.latitude.toFixed(4)}, ${memory.longitude.toFixed(4)}` : '');
function memoryMapMarkup(memory) { if (!Number.isFinite(memory.latitude) || !Number.isFinite(memory.longitude)) return ''; const lat = memory.latitude; const lng = memory.longitude; const delta = .012; const bbox = `${lng - delta},${lat - delta},${lng + delta},${lat + delta}`; const openUrl = `https://www.openstreetmap.org/?mlat=${encodeURIComponent(lat)}&mlon=${encodeURIComponent(lng)}#map=15/${encodeURIComponent(lat)}/${encodeURIComponent(lng)}`; return `<section class="memory-map"><div><span>⌖ ${escapeHtml(memoryLocationLabel(memory) || '기억의 장소')}</span><a href="${openUrl}" target="_blank" rel="noopener noreferrer">큰 지도 보기 ↗</a></div><iframe title="${escapeHtml(memory.title)} 위치 지도" src="https://www.openstreetmap.org/export/embed.html?bbox=${encodeURIComponent(bbox)}&layer=mapnik&marker=${encodeURIComponent(`${lat},${lng}`)}" loading="lazy"></iframe></section>`; }
function renderMemories() { const list = $('#memoryList'); const filters = $('#memoryFilters'); if (!list || !filters) return; refreshMemoryImageUrls(); const years = [...new Set(state.memories.map((memory) => (memory.date || '').slice(0, 4)).filter(Boolean))].sort().reverse(); if (activeMemoryFilter !== 'all' && !years.includes(activeMemoryFilter)) activeMemoryFilter = 'all'; filters.innerHTML = [`<button class="memory-filter ${activeMemoryFilter === 'all' ? 'is-active' : ''}" type="button" data-memory-filter="all">모든 추억</button>`, ...years.map((year) => `<button class="memory-filter ${activeMemoryFilter === year ? 'is-active' : ''}" type="button" data-memory-filter="${year}">${year}년</button>`)].join(''); const items = state.memories.filter((memory) => activeMemoryFilter === 'all' || memory.date?.startsWith(activeMemoryFilter)).sort((a, b) => (b.date || '').localeCompare(a.date || '')); list.innerHTML = items.length ? items.map((memory) => { const cover = memoryImageSource(memory.coverImage || memory.images[0]); const people = memoryPeople(memory); const location = memoryLocationLabel(memory); return `<article class="memory-card" data-open-memory="${memory.id}" tabindex="0" role="button"><div class="memory-card-cover ${cover ? '' : 'is-empty'}">${cover ? `<img src="${cover}" alt="${escapeHtml(memory.title)} 대표 사진" />` : '✦'}</div><div class="memory-card-body"><div class="memory-card-top"><span>${dateLabel(memory.date, memory.endDate)}</span><span>사진 ${memory.images.length}장</span></div><h3>${escapeHtml(memory.title)}</h3>${location ? `<span class="memory-location">⌖ ${escapeHtml(location)}</span>` : ''}${memory.story ? `<p>${escapeHtml(memory.story)}</p>` : '<p>아직 적어둔 이야기가 없어요.</p>'}<div>${memory.tags.slice(0, 3).map((tag) => `<span class="memory-tag">#${escapeHtml(tag)}</span>`).join('')}</div><div class="memory-card-foot"><span>${people.map((person) => escapeHtml(person.name)).join(' · ') || '나만의 순간'}</span><span>보기 →</span></div></div></article>`; }).join('') : '<div class="memory-empty">첫 번째 추억을 만들어보세요.<br />사진과 짧은 이야기만으로도 충분해요.</div>'; }
function renderPeople() { const list = $('#peopleList'); if (!list) return; list.innerHTML = state.people.length ? state.people.map((person) => { const count = state.memories.filter((memory) => memory.peopleIds.includes(person.id)).length; return `<article class="person-card" data-edit-person="${person.id}" tabindex="0" role="button"><span class="person-avatar">${escapeHtml(person.name.slice(0, 1))}</span><div><h3>${escapeHtml(person.name)}</h3><p>${escapeHtml(person.relation || person.note || '아직 적어둔 설명이 없어요.')}</p></div><span class="person-memory-count">추억 ${count}</span></article>`; }).join('') : '<div class="people-empty">가족, 친구, 동료처럼 소중한 사람부터 추가해보세요.</div>'; }
function renderMemoryPeopleOptions(selected = []) { const box = $('#memoryPeopleOptions'); box.innerHTML = state.people.length ? state.people.map((person) => `<label class="memory-person-option"><input type="checkbox" value="${person.id}" ${selected.includes(person.id) ? 'checked' : ''} />${escapeHtml(person.name)}${person.relation ? ` · ${escapeHtml(person.relation)}` : ''}</label>`).join('') : '<p class="upload-note">먼저 사람들 메뉴에서 인물을 추가하면 여기에서 연결할 수 있어요.</p>'; }
function showMemoryDraft() { const preview = $('#memoryImagePreview'); preview.innerHTML = memoryDraftImages.map((image, index) => `<img src="${image.preview}" alt="선택한 사진 미리보기 ${index + 1}" />`).join(''); }
function openMemoryDialog(id = null) { editingMemoryId = id; const memory = id ? state.memories.find((item) => item.id === id) : null; memoryDraftImages = []; memoryDraftCoordinates = Number.isFinite(memory?.latitude) && Number.isFinite(memory?.longitude) ? { latitude: memory.latitude, longitude: memory.longitude, locationQuery: memory.location || '' } : null; $('#memoryForm').reset(); $('#memoryDialogEyebrow').textContent = memory ? 'EDIT MEMORY' : 'NEW MEMORY'; $('#memoryDialogTitle').textContent = memory ? '추억을 다듬어보세요.' : '새로운 추억을 담아요.'; $('#memoryDate').value = memory?.date || new Date().toISOString().slice(0, 10); $('#memoryEndDate').value = memory?.endDate || ''; $('#memoryTitle').value = memory?.title || ''; $('#memoryLocation').value = memory?.location || ''; $('#memoryLocationStatus').textContent = memoryDraftCoordinates ? '지도 위치가 연결되어 있어요.' : ''; $('#memoryTags').value = memory?.tags?.join(', ') || ''; $('#memoryStory').value = memory?.story || ''; renderMemoryPeopleOptions(memory?.peopleIds || []); if (memory?.images?.length) memoryDraftImages = memory.images.map((src) => ({ preview: memoryImageSource(src), src, existing: true })); showMemoryDraft(); $('#memoryDialog').showModal(); $('#memoryTitle').focus(); }
async function imageDataUrl(file) { return new Promise((resolve) => { const reader = new FileReader(); reader.onload = () => resolve(reader.result); reader.readAsDataURL(file); }); }
async function uploadMemoryImage(file) { if (!signedInUser || !supabaseClient) return imageDataUrl(file); const { data: { session } } = await supabaseClient.auth.getSession(); if (!session?.access_token) throw new Error('로그인 세션을 찾지 못했어요. 로그아웃 후 다시 로그인해주세요.'); const ext = (file.name.split('.').pop() || 'jpg').replace(/[^a-z0-9]/gi, '').toLowerCase(); const path = `${signedInUser.id}/${newRecordId()}.${ext}`; const response = await fetch(`${SUPABASE_URL}/storage/v1/object/memory-images/${encodeURIComponent(path).replace(/%2F/g, '/')}`, { method: 'POST', headers: { apikey: SUPABASE_PUBLISHABLE_KEY, Authorization: `Bearer ${session.access_token}`, 'Content-Type': file.type, 'x-upsert': 'false' }, body: file }); if (!response.ok) { const detail = await response.text(); throw new Error(detail || `Storage 업로드 오류 (${response.status})`); } return path; }
function openMemoryDetail(id) { const memory = state.memories.find((item) => item.id === id); if (!memory) return; activeMemoryId = id; refreshMemoryImageUrls(); const people = memoryPeople(memory); $('#memoryDetailMeta').textContent = dateLabel(memory.date, memory.endDate); $('#memoryDetailTitle').textContent = memory.title; const photoMarkup = (image, index) => { const src = memoryImageSource(image); return src ? `<img src="${src}" alt="${escapeHtml(memory.title)} 사진 ${index + 1}" data-open-memory-image="${index}" />` : ''; }; const collage = memory.images.length ? `<div class="memory-collage">${memory.images.slice(0, 3).map(photoMarkup).join('')}</div>` : ''; const gallery = memory.images.length > 3 ? `<div class="memory-detail-gallery">${memory.images.slice(3).map((image, index) => photoMarkup(image, index + 3)).join('')}</div>` : ''; const locationOnly = memoryLocationLabel(memory) && !Number.isFinite(memory.latitude) ? `<p class="memory-detail-location">⌖ ${escapeHtml(memoryLocationLabel(memory))}</p>` : ''; $('#memoryDetailBody').innerHTML = `${collage}${locationOnly}${memoryMapMarkup(memory)}${memory.story ? `<p class="memory-detail-story">${escapeHtml(memory.story)}</p>` : '<p class="auth-intro">아직 적어둔 이야기가 없어요.</p>'}${memory.tags.length ? `<p>${memory.tags.map((tag) => `<span class="memory-tag">#${escapeHtml(tag)}</span>`).join('')}</p>` : ''}${people.length ? `<div class="memory-linked-people">${people.map((person) => `<button class="memory-linked-person" type="button" data-open-person="${person.id}">${escapeHtml(person.name)} →</button>`).join('')}</div>` : ''}${gallery}`; $('#memoryDetailDialog').showModal(); }
$('#addMemoryButton').addEventListener('click', () => openMemoryDialog());
$('#memoryImages').addEventListener('change', async (event) => { const files = [...event.target.files].filter((file) => file.type.startsWith('image/')); if (files.some((file) => file.size > 6 * 1024 * 1024)) { alert('사진 한 장은 6MB 이하로 선택해주세요.'); event.target.value = ''; return; } memoryDraftImages.push(...await Promise.all(files.map(async (file) => ({ file, preview: await imageDataUrl(file) })))); showMemoryDraft(); event.target.value = ''; });
async function geocodeMemoryLocation({ quiet = false } = {}) { const location = $('#memoryLocation').value.trim(); const status = $('#memoryLocationStatus'); if (!location) { memoryDraftCoordinates = null; status.textContent = ''; return false; } if (memoryDraftCoordinates?.locationQuery === location) return true; status.textContent = '장소를 지도에서 찾는 중…'; try { const response = await fetch(`https://nominatim.openstreetmap.org/search?format=jsonv2&limit=1&accept-language=ko&q=${encodeURIComponent(location)}`); if (!response.ok) throw new Error('location search failed'); const results = await response.json(); if (!results.length) throw new Error('location not found'); memoryDraftCoordinates = { latitude: Number(results[0].lat), longitude: Number(results[0].lon), locationQuery: location }; status.textContent = '지도 위치를 연결했어요.'; return true; } catch (error) { console.warn(error); memoryDraftCoordinates = null; status.textContent = quiet ? '지도 위치를 찾지 못했어요.' : '장소를 찾지 못했어요. 더 구체적인 장소명으로 적어주세요.'; return false; } }
$('#memoryLocation').addEventListener('change', () => { geocodeMemoryLocation({ quiet: true }); });
$('#useCurrentLocationButton').addEventListener('click', () => { const status = $('#memoryLocationStatus'); if (!navigator.geolocation) { status.textContent = '이 브라우저는 위치 정보를 지원하지 않아요.'; return; } status.textContent = '현재 위치와 지역명을 확인 중…'; navigator.geolocation.getCurrentPosition(async (position) => { const latitude = position.coords.latitude; const longitude = position.coords.longitude; memoryDraftCoordinates = { latitude, longitude }; try { const response = await fetch(`https://nominatim.openstreetmap.org/reverse?format=jsonv2&accept-language=ko&lat=${encodeURIComponent(latitude)}&lon=${encodeURIComponent(longitude)}`); if (!response.ok) throw new Error('reverse geocoding failed'); const result = await response.json(); const address = result.address || {}; const parts = [address.neighbourhood || address.suburb || address.village || address.town || address.city_district, address.city || address.county || address.state].filter(Boolean); $('#memoryLocation').value = [...new Set(parts)].join(' · ') || result.display_name || ''; status.textContent = '현재 위치의 지역명을 담았어요.'; } catch (error) { console.warn(error); status.textContent = '지도 위치는 저장했어요. 장소명은 직접 적어주세요.'; } }, () => { status.textContent = '위치를 가져오지 못했어요. 권한을 확인해주세요.'; }, { enableHighAccuracy: true, timeout: 10000, maximumAge: 300000 }); });
$('#memoryForm').addEventListener('submit', async (event) => { event.preventDefault(); const title = $('#memoryTitle').value.trim(); if (!title) return; const saveButton = $('#memoryForm .save-button'); saveButton.disabled = true; saveButton.textContent = '사진 저장 중…'; try { await geocodeMemoryLocation({ quiet: true }); const images = await Promise.all(memoryDraftImages.map((image) => image.existing ? image.src : uploadMemoryImage(image.file))); const previous = editingMemoryId ? state.memories.find((item) => item.id === editingMemoryId) : null; const memory = { id: previous?.id || newRecordId(), title, date: $('#memoryDate').value, endDate: $('#memoryEndDate').value, location: $('#memoryLocation').value.trim(), latitude: memoryDraftCoordinates?.latitude ?? null, longitude: memoryDraftCoordinates?.longitude ?? null, story: $('#memoryStory').value.trim(), tags: $('#memoryTags').value.split(',').map((tag) => tag.trim()).filter(Boolean).slice(0, 10), peopleIds: [...document.querySelectorAll('#memoryPeopleOptions input:checked')].map((input) => input.value), images, coverImage: previous?.coverImage && images.includes(previous.coverImage) ? previous.coverImage : images[0] || '', createdAt: previous?.createdAt || new Date().toISOString() }; if (previous) state.memories[state.memories.findIndex((item) => item.id === previous.id)] = memory; else state.memories.push(memory); persist(); render(); $('#memoryDialog').close(); } catch (error) { console.error(error); const message = String(error?.message || ''); const setupIssue = /bucket|row-level|permission|not authorized|policy/i.test(message); alert(setupIssue ? `사진 저장 권한이 아직 준비되지 않았어요. Supabase SQL Editor에서 supabase-schema.sql을 실행해주세요.\n\n오류: ${message}` : `사진을 저장하지 못했어요. 다시 시도해주세요.\n\n오류: ${message || '알 수 없음'}`); } finally { saveButton.disabled = false; saveButton.textContent = '추억 저장'; } });
$('#memoryFilters').addEventListener('click', (event) => { const button = event.target.closest('[data-memory-filter]'); if (!button) return; activeMemoryFilter = button.dataset.memoryFilter; renderMemories(); });
$('#memoryList').addEventListener('click', (event) => { const card = event.target.closest('[data-open-memory]'); if (card) openMemoryDetail(card.dataset.openMemory); });
