$('#memoryDetailBody').addEventListener('click', (event) => { const image = event.target.closest('[data-open-memory-image]'); if (!image) return; $('#imageDialogPreview').src = image.src; $('#imageDialogPreview').alt = image.alt; imageDialog.showModal(); });
function hideMemoryPhotoContextMenu() { $('#memoryPhotoContextMenu').hidden = true; contextMemoryImageIndex = null; }
$('#memoryDetailDialog').addEventListener('close', () => { activeMemoryId = null; hideMemoryPhotoContextMenu(); });
$('#memoryDetailBody').addEventListener('contextmenu', (event) => { const image = event.target.closest('[data-open-memory-image]'); if (!image) { hideMemoryPhotoContextMenu(); return; } event.preventDefault(); contextMemoryImageIndex = Number(image.dataset.openMemoryImage); const menu = $('#memoryPhotoContextMenu'); menu.hidden = false; const maxLeft = window.innerWidth - menu.offsetWidth - 10; const maxTop = window.innerHeight - menu.offsetHeight - 10; menu.style.left = `${Math.max(10, Math.min(event.clientX, maxLeft))}px`; menu.style.top = `${Math.max(10, Math.min(event.clientY, maxTop))}px`; });
$('#setMemoryCoverButton').addEventListener('click', () => { const memory = state.memories.find((item) => item.id === activeMemoryId); const image = memory?.images[contextMemoryImageIndex]; if (!memory || !image) return hideMemoryPhotoContextMenu(); memory.coverImage = image; persist(); renderMemories(); hideMemoryPhotoContextMenu(); });
document.addEventListener('click', (event) => { if (!event.target.closest('#memoryPhotoContextMenu')) hideMemoryPhotoContextMenu(); });
window.addEventListener('resize', hideMemoryPhotoContextMenu);
$('#editMemoryButton').addEventListener('click', () => { const id = activeMemoryId; $('#memoryDetailDialog').close(); openMemoryDialog(id); });
async function deleteMemoryStorageFiles(memory) { const paths = memory.images.filter((image) => image && !isLocalMemoryImage(image)); if (!paths.length || !signedInUser || !supabaseClient) return; const { error } = await supabaseClient.storage.from('memory-images').remove(paths); if (error) throw error; paths.forEach((path) => memoryImageUrlCache.delete(path)); }
$('#deleteMemoryButton').addEventListener('click', async () => { const memory = state.memories.find((item) => item.id === activeMemoryId); if (!memory || !confirm(`“${memory.title}” 추억과 저장된 사진을 모두 삭제할까요?`)) return; const button = $('#deleteMemoryButton'); button.disabled = true; button.textContent = '사진 삭제 중…'; try { await deleteMemoryStorageFiles(memory); state.memories = state.memories.filter((item) => item.id !== activeMemoryId); persist(); render(); $('#memoryDetailDialog').close(); } catch (error) { console.error(error); alert('사진 원본을 삭제하지 못해 앨범 삭제를 취소했어요. 다시 시도해주세요.'); } finally { button.disabled = false; button.textContent = '삭제'; } });
